# 合併10年資料
mu_all = pd.concat([mu100_tidy,mu101_tidy,mu102_tidy,mu103_tidy,mu104_tidy,mu105_tidy,mu106_tidy,mu107_tidy, mu108_tidy,mu109_tidy], ignore_index=True)

# 做變數轉換、生成所需的虛擬變數
# 先挑選出所有人是全職工作者，再篩選出月薪資大於100的人，以確保沒人填錯資訊。
# 排除婚姻狀況是喪偶和離婚者
mu_all_tidy = mu_all[(mu_all['wage']>100) & (mu_all['fulltime'] == 1) & ((mu_all['marriage'] == 1) | (mu_all['marriage'] == 2))  ]

# 生成所需的虛擬變數
mu_all_tidy['gender'] = mu_all_tidy['gender'] - 1
mu_all_tidy['marriage'] = mu_all_tidy['marriage'] - 1
mu_all_tidy['lwage'] = np.log(mu_all_tidy['wage'])  # 薪資取log可以讓解釋變數以百分比為單位
mu_all_tidy['gender_marriage'] = mu_all_tidy['gender'] * mu_all_tidy['marriage']

# 將教育程度轉換成教育年數
def assign_yedu(edu):
  if edu == 10:
    return 24
  elif edu == 9:
    return 18
  elif edu == 8:
    return 16
  elif edu == 7:
    return 12
  elif edu == 6:
    return 12
  elif edu == 5:
    return 12
  elif edu == 4:
    return 9
  elif edu == 3:
    return 6
  else:
    return 0

# 將小孩數量轉換成有無養育小孩
def assign_have_children(children):
  if children > 0:
    return 1
  else:
    return 0

# 先將各工作類型轉換成0/1，再指定工作類型名稱(工作類型轉換成虛擬變數的意思)
def assign_self_employed(work_type):
  if work_type == 2:
    return 1
  else:
    return 0

def assign_public(work_type):
  if work_type == 3:
    return 1
  else:
    return 0

def assign_private(work_type):
  if work_type == 4:
    return 1
  else:
    return 0

# 將work_type轉換成虛擬變數
mu_all_tidy['self_employed'] = mu_all_tidy['work_type'].apply(assign_self_employed)
mu_all_tidy['public'] = mu_all_tidy['work_type'].apply(assign_public)
mu_all_tidy['private'] = mu_all_tidy['work_type'].apply(assign_private)

mu_all_tidy['yedu'] = mu_all_tidy['edu'].apply(assign_yedu)
mu_all_tidy['age_square']  = mu_all_tidy['age'] **2
mu_all_tidy['have_children'] = mu_all_tidy['children'].apply(assign_have_children)
mu_all_tidy['gender_have_children']  = mu_all_tidy['gender'] * mu_all_tidy['have_children']

print(mu_all_tidy)

"""##Model (1)
只考慮我們在乎的變數: 性別、婚姻狀況、有無小孩

$$
\text{log(wage)}=\beta_0+\beta_1\text{gender}+\beta_2\text{marriage}+\beta_3\text{gender}×\text{marriage}+\beta_4\text{have children}+ϵ
$$

"""

#benchmark
X1 = pd.concat([mu_all_tidy[['gender', 'marriage', 'gender_marriage','have_children']]], axis=1)
y = mu_all_tidy['lwage']
X1 = sm.add_constant(X1)
model_1 = sm.OLS(y, X1).fit(cov_type='HC1')

print(model_1.summary())

"""##Model (2)
多考慮了養育小孩對男女的效果可能不同

$$
\begin{align*}
\text{log(wage)}=\beta_0&+\beta_1\text{gender}+\beta_2\text{marriage}+\beta_3\text{gender}×\text{marriage}+\beta_4\text{have children} \\
&+\beta_5\text{gender}×\text{have children}+ϵ
\end{align*}
$$
"""

X2 = pd.concat([mu_all_tidy[['gender', 'marriage', 'gender_marriage','have_children','gender_have_children']]], axis=1)
y = mu_all_tidy['lwage']
X2 = sm.add_constant(X2)
model_2 = sm.OLS(y, X2).fit(cov_type='HC1')
print(model_2.summary())

##跑回歸結果發現有小孩的薪水較高，可能是反向因果

"""##Model (3)
加入我們認為有關的變數當作控制項

$$
\begin{align*}
\text{log(wage)}=\beta_0&+\beta_1\text{gender}+\beta_2\text{marriage}+\beta_3\text{gender}×\text{marriage}+\beta_4\text{have children} \\
&+\beta_5\text{gender}×\text{have children}+\gamma_1\text{age}+\gamma_2\text{private}+\gamma_3\text{public}+\gamma_4\text{self employed}\\ &+\gamma_5\text{work time}+\gamma_6\text{years of edu}+ϵ
\end{align*}
$$
"""

X3 = pd.concat([mu_all_tidy[['gender', 'marriage', 'gender_marriage','have_children','gender_have_children','age','yedu','work_time','self_employed','public','private']]], axis=1)
X3 = sm.add_constant(X3)  #加上截距項

model_3 = sm.OLS(y, X3).fit(cov_type='HC1')  # 調整變異數 Robust Standard Error(針對異質變異)
print(model_3.summary())

"""![Screenshot 2024-12-29 154039.png](data:image/png;base64,)

"""

stargazer = Stargazer([model_1, model_2, model_3])
print(stargazer.render_latex())  # 输出 LaTeX 格式

"""$$\begin{align*}
\text{log(wage)} &= \beta_0 + \beta_1 \text{gender} + \beta_2 \text{marriage} + \beta_3 \text{gender} \times \text{marriage} + \beta_4 \text{have children} + \epsilon \\
\text{log(wage)} &= \beta_0 + \beta_1 \text{gender} + \beta_2 \text{marriage} + \beta_3 \text{gender} \times \text{marriage} + \beta_4 \text{have children} \\
& \quad + \beta_5 \text{gender} \times \text{have children} + \epsilon \\
\text{log(wage)} &= \beta_0 + \beta_1 \text{gender} + \beta_2 \text{marriage} + \beta_3 \text{gender} \times \text{marriage} + \beta_4 \text{have children} \\
& \quad + \beta_5 \text{gender} \times \text{have children} + \gamma_1 \text{age} + \gamma_2 \text{private} + \gamma_3 \text{public} \\
& \quad + \gamma_4 \text{self employed} + \gamma_5 \text{work time} + \gamma_6 \text{years of edu} + \epsilon
\end{align*}$$

$$\begin{align*}
X &\Rightarrow \log X \\
\frac{dlog X}{dX}&=\frac{1}{X} \\
\Delta \log X \cdot 100\% &\approx \Delta X/X=\%\Delta X
\end{align*}$$

![Screenshot 2024-12-29 162217.png](data:image/png;base64,)

###異質變異數檢測_BP test
H0:同質變異數

H1:異質變異數

拒絕H0

BPtest有兩種測法 LM統計量和F統計量
"""

bp_test = sms.het_breuschpagan(model_3.resid, model_3.model.exog)

print(bp_test)
print("Breusch-Pagan Test results:")
print("LM Statistic:",bp_test[0])
print("p-value:" ,bp_test[1])  # LM statistic

"""##GVIF"""

vif_data = pd.DataFrame()
